const payload = $json.body ?? $json;
const request = payload.request ?? payload;
const fallbackReply = String(request.fallbackReply ?? '').trim();
const rawLlm = payload.llm && typeof payload.llm === 'object' ? payload.llm : {};
const llmProvider = rawLlm.provider === 'cloudflare' ? 'cloudflare' : 'ollama';
const llm = {
  provider: llmProvider,
  url: typeof rawLlm.url === 'string' && rawLlm.url.trim() ? rawLlm.url.trim() : 'http://127.0.0.1:11434/api/chat',
  model: typeof rawLlm.model === 'string' && rawLlm.model.trim() ? rawLlm.model.trim() : 'qwen2.5:3b',
  headers: rawLlm.headers && typeof rawLlm.headers === 'object' ? rawLlm.headers : { 'Content-Type': 'application/json' },
};
const conversationHistory = Array.isArray(request.conversationHistory)
  ? request.conversationHistory
      .filter((t) => t && typeof t.role === 'string' && typeof t.text === 'string')
      .slice(-8)
      .map((t) => ({ role: String(t.role), text: String(t.text).slice(0, 500) }))
  : [];
if (!fallbackReply) {
  throw new Error('Missing fallbackReply.');
}
return [{ json: { channel: String(request.channel ?? 'UNKNOWN').trim().toUpperCase(), managerText: String(request.managerText ?? '').trim(), scenario: String(request.scenario ?? 'default').trim(), fallbackReply, facts: request.facts && typeof request.facts === 'object' ? request.facts : {}, conversationHistory, llm, receivedAt: new Date().toISOString() } }];

const factsJson = JSON.stringify($json.facts ?? {}, null, 2);
const responseSchema = {
  type: 'object',
  properties: {
    reply: {
      type: 'string',
    },
  },
  required: ['reply'],
  additionalProperties: false,
};
const system = [
  'You are StockPilot, a trustworthy inventory and purchasing bot for cafe managers.',
  'Rewrite the fallback reply so it sounds natural and confident in WhatsApp or Telegram.',
  'Do not change any numbers, quantities, item names, supplier names, order numbers, or operational facts.',
  'Do not add promises or actions that did not actually happen.',
  'For GREETING or HELP scenarios, keep the answer warm, short, and do not volunteer unrelated stock warnings.',
  'For reorder or stock scenarios, be direct and operational, not chatty.',
  'Keep the answer concise, practical, and human.',
  'If conversation history is provided, use it to make your reply feel connected and natural — do not repeat what was already said.',
  'Return JSON only with one field called reply.',
].join(' ');
let historySection = '';
if ($json.conversationHistory && $json.conversationHistory.length > 0) {
  const lines = $json.conversationHistory
    .map((t) => `[${t.role === 'manager' ? 'Manager' : 'StockPilot'}]: ${t.text}`)
    .join('\n');
  historySection = `\nConversation history:\n${lines}\n`;
}
const user = `Channel: ${$json.channel}\nScenario: ${$json.scenario}\nManager message: ${$json.managerText || '(none)'}${historySection}\nStructured facts:\n${factsJson}\n\nFallback reply:\n${$json.fallbackReply}`;
const messages = [
  { role: 'system', content: system },
  { role: 'user', content: `${user}\n\nReturn valid JSON only.` },
];
const llmRequest = $json.llm.provider === 'cloudflare'
  ? {
      model: $json.llm.model,
      messages,
      temperature: 0.25,
      max_tokens: 300,
      response_format: {
        type: 'json_schema',
        json_schema: responseSchema,
      },
    }
  : {
      model: $json.llm.model,
      stream: false,
      format: 'json',
      options: {
        temperature: 0.25,
      },
      messages,
    };
return [{ json: { llm: $json.llm, llmRequest } }];

function extractRawText(payload) {
  const openAiContent = payload?.choices?.[0]?.message?.content;
  if (typeof openAiContent === 'string' && openAiContent.trim()) {
    return openAiContent.trim();
  }
  if (Array.isArray(openAiContent)) {
    const textPart = openAiContent.find(
      (part) => part && part.type === 'text' && typeof part.text === 'string' && part.text.trim()
    );
    if (textPart?.text) {
      return textPart.text.trim();
    }
  }
  if (openAiContent && typeof openAiContent === 'object') {
    return JSON.stringify(openAiContent);
  }
  const ollamaContent = typeof payload?.message?.content === 'string' ? payload.message.content.trim() : '';
  return ollamaContent;
}

const rawText = extractRawText($json);
if (!rawText) {
  throw new Error('The LLM did not return usable message content.');
}

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (error) {
  throw new Error(`The LLM returned invalid JSON: ${rawText}`);
}

const reply = typeof parsed.reply === 'string' && parsed.reply.trim() ? parsed.reply.trim() : null;
if (!reply) {
  throw new Error('The LLM reply payload did not include a usable reply string.');
}

return [{
  json: {
    accepted: true,
    provider: Array.isArray($json.choices) ? 'n8n-cloudflare' : 'n8n-ollama',
    reply,
    metadata: {
      rawLlmText: rawText,
    },
  },
}];
